#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include <time.h>
#include <cuda_runtime.h>

#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000

struct neighbor {
    char entry[REC_LENGTH];
    double dist;
};

__device__ float device_atof_simple(const char *s) {
    while (*s == ' ' || *s == '\t') s++;

    int sign = 1;
    if (*s == '-') {
        sign = -1;
        s++;
    } else if (*s == '+') {
        s++;
    }

    float val = 0.0f;
    while (*s >= '0' && *s <= '9') {
        val = val * 10.0f + (float)(*s - '0');
        s++;
    }

    if (*s == '.') {
        s++;
        float frac = 0.1f;
        while (*s >= '0' && *s <= '9') {
            val += (float)(*s - '0') * frac;
            frac *= 0.1f;
            s++;
        }
    }

    return sign * val;
}

__global__ void compute_distances_kernel(const char *sandbox, float *z, int rec_count, float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
        const char *rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);
        float tmp_lat = device_atof_simple(rec_iter);
        float tmp_long = device_atof_simple(rec_iter + 5);
        z[i] = sqrtf(((tmp_lat - target_lat) * (tmp_lat - target_lat)) +
                     ((tmp_long - target_long) * (tmp_long - target_long)));
    }
}

int main(int argc, char* argv[]) {
    long long time0 = clock();
    FILE *flist, *fp;
    int i = 0, j = 0, k = 0, rec_count = 0, done = 0;
    char sandbox[REC_LENGTH * REC_WINDOW], *rec_iter, *rec_iter2, dbname[64];
    struct neighbor *neighbors = NULL;
    float target_lat, target_long, tmp_lat = 0, tmp_long = 0;

    if (argc < 5) {
        fprintf(stderr, "Invalid set of arguments\n");
        exit(-1);
    }

    flist = fopen(argv[1], "r");
    if (!flist) {
        printf("error opening flist\n");
        exit(1);
    }

    k = atoi(argv[2]);
    target_lat = (float)atof(argv[3]);
    target_long = (float)atof(argv[4]);

    neighbors = (struct neighbor *)malloc(k * sizeof(struct neighbor));

    if (neighbors == NULL) {
        fprintf(stderr, "no room for neighbors\n");
        exit(0);
    }

    for (j = 0; j < k; j++) {
        neighbors[j].dist = OPEN;
    }

    if (fscanf(flist, "%s\n", dbname) != 1) {
        fprintf(stderr, "error reading filelist\n");
        exit(0);
    }

    fp = fopen(dbname, "r");
    if (!fp) {
        printf("error opening flist\n");
        exit(1);
    }

    float *z;
    z = (float *)malloc(REC_WINDOW * sizeof(float));

    char *d_sandbox = NULL;
    float *d_z = NULL;
    cudaMalloc((void **)&d_sandbox, REC_LENGTH * REC_WINDOW * sizeof(char));
    cudaMalloc((void **)&d_z, REC_WINDOW * sizeof(float));

    while (!done) {
        rec_count = (int)fread(sandbox, REC_LENGTH, REC_WINDOW, fp);
        if (rec_count != REC_WINDOW) {
            if (!ferror(flist)) {
                fclose(fp);

                if (feof(flist))
                    done = 1;
                else {
                    if (fscanf(flist, "%s\n", dbname) != 1) {
                        fprintf(stderr, "error reading filelist\n");
                        exit(0);
                    }

                    fp = fopen(dbname, "r");

                    if (!fp) {
                        printf("error opening a db\n");
                        exit(1);
                    }
                }
            } else {
                perror("Error");
                exit(0);
            }
        }

        if (rec_count > 0) {
            cudaMemcpy(d_sandbox, sandbox, REC_LENGTH * REC_WINDOW * sizeof(char), cudaMemcpyHostToDevice);
            int blockSize = 256;
            int gridSize = (rec_count + blockSize - 1) / blockSize;
            compute_distances_kernel<<<gridSize, blockSize>>>(d_sandbox, d_z, rec_count, target_lat, target_long);
            cudaDeviceSynchronize();
            cudaMemcpy(z, d_z, REC_WINDOW * sizeof(float), cudaMemcpyDeviceToHost);
        }

        for (i = 0; i < rec_count; i++) {
            float max_dist = -1;
            int max_idx = 0;

            for (j = 0; j < k; j++) {
                if (neighbors[j].dist > max_dist) {
                    max_dist = (float)neighbors[j].dist;
                    max_idx = j;
                }
            }

            if (z[i] < neighbors[max_idx].dist) {
                sandbox[(i + 1) * REC_LENGTH - 1] = '\0';
                strcpy(neighbors[max_idx].entry, sandbox + i * REC_LENGTH);
                neighbors[max_idx].dist = z[i];
            }
        }
    }

    fprintf(stderr, "The %d nearest neighbors are:\n", k);
    for (j = 0; j < k; j++) {
        if (!(neighbors[j].dist == OPEN))
            fprintf(stderr, "%s --> %f\n", neighbors[j].entry, neighbors[j].dist);
    }

    fclose(flist);

    cudaFree(d_sandbox);
    cudaFree(d_z);
    free(z);
    free(neighbors);

    long long time1 = clock();
    printf("total time : %15.12f s", (float)(time1 - time0) / 1000000);
    return 0;
}
